create table if not exists analytics.metric_snapshots (id bigserial primary key, metric_key text not null, module text not null, metric_value numeric, metric_payload jsonb not null default '{}'::jsonb, source_of_truth text not null, trust_label text not null check (trust_label in ('high','medium','low','untrusted')), formula_version text not null, freshness_at timestamptz, calculated_at timestamptz not null default now(), owner text not null default 'analytics', constraint no_manual_trust_elevation check ((metric_payload->>'manual_trust_elevation') is null));
